29	const CURSED_SURCHARGE_RATE = 0.5;
30	const HIGH_ENCHANTMENT_THRESHOLD = 5;
31	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
32	
33	const basePremiumFor = (type: string): number => BASE_PREMIUMS[type] ?? 0;
34	
35	const itemSurcharge = (item: Item): number => {
36	  const base = basePremiumFor(item.type);
37	  let surcharge = 0;
38	  if (item.cursed) {
39	    surcharge += base * CURSED_SURCHARGE_RATE;
40	  }
