47	const quotePremium = (items: Array<Item>): number => {
48	  const typeCounts: Record<string, number> = {};
49	  for (const item of items) {
50	    typeCounts[item.type] = (typeCounts[item.type] ?? 0) + 1;
51	  }
52	  let total = 0;
53	  for (const [type, count] of Object.entries(typeCounts)) {
54	    if (count === COMPONENT_BLOCK_SIZE) {
55	      total += COMPONENT_BLOCK_PRICE;
56	    } else {
57	      total += count * basePremiumFor(type);
58	    }
59	  }
60	  for (const item of items) {
61	    total += itemSurcharge(item);
62	  }
63	  return total + PROCESSING_FEE;
64	};
65	
66	export const processSteps = (customer: Customer, steps: Array<{ op: string; items: Array<Item> }>): Array<QuoteResult> =>
67	  steps.map((step) => ({
68	    premium: quotePremium(step.items),
