const quotePremium = (items: Array<Item>): number => {
  const typeCounts: Record<string, number> = {};
  for (const item of items) {
    typeCounts[item.type] = (typeCounts[item.type] ?? 0) + 1;
  }
  let policyBasePremium = 0;
  for (const [type, count] of Object.entries(typeCounts)) {
    if (count === COMPONENT_BLOCK_SIZE) {
      policyBasePremium += COMPONENT_BLOCK_PRICE;
    } else {
      policyBasePremium += count * basePremiumFor(type);
    }
  }
  let totalSurcharges = 0;
  for (const item of items) {
    totalSurcharges += itemSurcharge(item);
  }
  const firstInsurance = policyBasePremium * FIRST_INSURANCE_RATE;
  return policyBasePremium + totalSurcharges + firstInsurance + PROCESSING_FEE;
};

